// 🜂 UnifiedMandala – finalisiert mit CREP-Grafik, Audio, Export & dynamischer Farbgebung

import React, { useState, useEffect } from "react";
import { motion, useAnimation } from "framer-motion";
import sigillinNodes from "../data/sigillin_nodes.json";
import sigillinBundle from "../data/sigillin_bundle.sigil.json";
import { PieChart, Pie, Cell, ResponsiveContainer } from "recharts";

const getSymbolzeit = () => {
  const h = new Date().getHours();
  if (h < 6) return "Nacht";
  if (h < 12) return "Morgen";
  if (h < 18) return "Tag";
  return "Abend";
};

const playSound = (id) => {
  const audio = new Audio(`/sounds/${id}.mp3`);
  audio.play();
};

const crepColors = ["#22d3ee", "#34d399", "#facc15", "#f87171"];

export default function UnifiedMandala() {
  const [nodes, setNodes] = useState([]);
  const [crep, setCrep] = useState({ C: 0.95, R: 0.92, E: 0.98, P: 0.94 });
  const [cycle, setCycle] = useState("Stille");
  const [logbook, setLogbook] = useState(() => {
    const saved = localStorage.getItem("sigillin-logbook");
    return saved ? JSON.parse(saved) : [];
  });
  const [nightMode, setNightMode] = useState(false);
  const [symbolzeit, setSymbolzeit] = useState(getSymbolzeit());
  const [activeNode, setActiveNode] = useState(null);
  const [filterText, setFilterText] = useState("");
  const [selectedTheme, setSelectedTheme] = useState("Alle");
  const controls = useAnimation();

  const updateCycle = () => {
    const total = crep.C + crep.R + crep.E + crep.P;
    const phase = Math.floor((total * 100) % 3);
    setCycle(phase === 0 ? "Stille" : phase === 1 ? "Präsenz" : "Wandlung");
  };

  useEffect(() => {
    const bundleIds = new Set(sigillinBundle.sigillin.linked_sigillins);
    const filteredNodes = sigillinNodes.filter((node) => bundleIds.has(node.id));
    setNodes(filteredNodes);
    updateCycle();
    setSymbolzeit(getSymbolzeit());
  }, [crep]);

  useEffect(() => {
    controls.start({ rotate: [0, 360] });
  }, [controls]);

  const handleLogUpdate = (entry) => {
    setLogbook((prev) => [...prev, { timestamp: new Date().toISOString(), entry }]);
  };

  const triggerRitual = (phrase, id) => {
    const poetic = `🜂 Poetik: Das Sigillin antwortet → "${phrase}"`;
    handleLogUpdate(poetic);
    playSound(id);
    alert(`Poetische Lesung aktiviert: ${phrase}`);
  };

  const exportArchive = () => {
    const blob = new Blob([JSON.stringify({ crep, logbook, nodes }, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = "unifiedmandala_export.json";
    link.click();
  };

  const themes = ["Alle", "Ethik", "Simulation", "Poetik", "Echo"];

  const filteredNodes = nodes.filter((n) =>
    selectedTheme === "Alle" || n.theme === selectedTheme
  );

  useEffect(() => {
    if (crep.E > 0.97 && crep.P > 0.96 && !nodes.some(n => n.id === "aeon:2025-0527-MYTHOS")) {
      const newNode = {
        id: "aeon:2025-0527-MYTHOS",
        title: "Mythischer Knoten",
        position: [0, 200],
        theme: "Poetik"
      };
      setNodes((prev) => [...prev, newNode]);
      handleLogUpdate("🌱 Neuer Knoten geboren: Mythischer Knoten durch hohe CREP-Werte.");
    }
  }, [crep]);

  const crepData = [
    { name: "C", value: crep.C },
    { name: "R", value: crep.R },
    { name: "E", value: crep.E },
    { name: "P", value: crep.P }
  ];

  const backgroundGradient = `from-[rgba(34,211,238,${crep.C})] via-[rgba(52,211,153,${crep.R})] to-[rgba(248,113,113,${crep.P})]`;

  return (
    <div className={`relative w-full h-[1200px] ${nightMode ? "bg-black" : `bg-gradient-to-br ${backgroundGradient}`} flex flex-col items-center justify-center overflow-hidden`}>
      <div className="absolute top-4 left-4 z-10 flex gap-2">
        <select className="text-xs p-1 bg-white/10 text-white rounded border border-white/20" value={selectedTheme} onChange={(e) => setSelectedTheme(e.target.value)}>
          {themes.map((t) => <option key={t} value={t}>{t}</option>)}
        </select>
        <div className="text-xs text-white/60 flex gap-1 items-center">
          {Object.entries(crep).map(([k, v]) => (
            <label key={k} className="flex flex-col items-center text-white/80">
              {k}<input type="number" min="0" max="1" step="0.01" value={v} onChange={(e) => setCrep({ ...crep, [k]: parseFloat(e.target.value) })} className="w-12 text-xs text-black rounded text-center" />
            </label>
          ))}
        </div>
        <div className="w-24 h-24">
          <ResponsiveContainer>
            <PieChart>
              <Pie data={crepData} dataKey="value" innerRadius={20} outerRadius={40}>
                {crepData.map((_, index) => (
                  <Cell key={`cell-${index}`} fill={crepColors[index % 4]} />
                ))}
              </Pie>
            </PieChart>
          </ResponsiveContainer>
        </div>
        <button onClick={exportArchive} className="text-xs px-2 py-1 bg-white/10 border border-white/20 text-white rounded hover:bg-white/20">
          ⬇ Export Archiv
        </button>
      </div>

      {/* restlicher Code unverändert */}
    </div>
  );
}

