 * Modul: CREPManager.ts
 * Beschreibung: Zustandsverwaltung, Verlaufsspeicherung und Schwellenlogik
 */

export const defaultCREP = { C: 0.95, R: 0.92, E: 0.98, P: 0.94 };

export class CREPManager {
  constructor(storageKey = 'crep-history') {
    this.crep = { ...defaultCREP };
    this.history = JSON.parse(localStorage.getItem(storageKey) || '[]');
    this.storageKey = storageKey;
  }

  update(newValues) {
    this.crep = { ...this.crep, ...newValues };
    this.history.push({ ...this.crep, timestamp: Date.now() });
    localStorage.setItem(this.storageKey, JSON.stringify(this.history));
    this.checkEmergence();
  }

